# rocketmq_knowledge_dict.py """ 本地可用的 RocketMQ KnowledgeDict - 用于多轮 MockChain / RuleChain Agent 本地调试 - 包含 ISR、Broker、Controller、常见故障及指标 - 包含 K8s 部署信息和管理方法 - 包含日志路径信息 """
ROCKETMQ_KNOWLEDGE = { "isr": { "定义": "ISR 是 In-Sync Replicas，表示与主副本同步的 broker 列表。", "移出原因": [ "heartbeat timeout", "replication lag 超过阈值", "broker JVM GC 暂停过长", "网络抖动", "磁盘 IO 瓶颈" ], "影响": "消息副本数量下降，消费延迟增加" }, "broker": { "role": ["Master", "Slave"], "常见指标": [ "flush latency", "disk usage", "in/out of ISR", "replication lag", "heap usage" ], "常见异常日志关键词": [ "remove broker from ISR", "not in sync state", "flush latency high", "replication stalled" ] }, "controller": { "作用": "管理 ISR 列表，处理 broker 状态变更", "常见日志关键词": [ "remove broker from ISR", "heartbeat timeout" ] }, "common_actions": { "heartbeat timeout": [ "检查 broker 与 controller 网络连接", "查看 broker 心跳日志", "排查防火墙或网络延迟" ], "replication lag 超过阈值": [ "查看 broker 刷盘速度", "检查磁盘 IO", "评估 broker 是否需要扩容" ], "broker JVM GC 暂停过长": [ "检查 broker GC 日志", "调整 JVM 内存参数", "必要时重启 broker" ], "网络抖动": [ "ping 测试 broker 与 controller", "检查交换机 / 路由器", "查看网络日志" ], "磁盘 IO 瓶颈": [ "查看磁盘使用率", "使用 iostat / vmstat 排查", "迁移或扩容磁盘" ] }, "k8s_deployment": { "说明": "RocketMQ 部署在 Kubernetes 上", "组件": { "namesrv": { "类型": "注册中心", "pod_container": ["namesrv", "sidecar"], "管理方式": [ "登录 namesrv pod 的 namesrv 进程容器", "通过 bin/mqadmin 调用 admin api", "不输入参数时打印 help 信息" ], "日志路径": "~/logs/rocketmqlogs/" }, "broker": { "类型": "存储节点", "pod_container": ["broker", "sidecar"], "管理方式": [ "登录 broker pod 的 broker 进程容器", "通过 bin/mqadmin 调用 admin api", "不输入参数时打印 help 信息" ], "日志路径": "~/logs/rocketmqlogs/" } }, "kubectl_command": "关键命令 kubectl get pod -n rocketmq5" } }
# generate_agent_prompt.py """ 将本地 RocketMQ KnowledgeDict 转化为多轮 Agent Prompt - 每轮分析可动态加入最新 Evidence """
from typing import Dict, List
def generate_agent_prompt(evidences: List[Dict] = None) -> str: evidences = evidences or []
prompt_lines = [] prompt_lines.append("你是一名 RocketMQ 专家，正在协助分析集群异常。请参考以下基础知识：
")
# ISR 知识 isr = ROCKETMQ_KNOWLEDGE['isr'] prompt_lines.append(f"1. ISR（In-Sync Replicas）
 - 定义：{isr['定义']}
 - 移出原因：{', '.join(isr['移出原因'])}
 - 影响：{isr['影响']}
")
# Broker 知识 broker = ROCKETMQ_KNOWLEDGE['broker'] prompt_lines.append(f"2. Broker
 - 角色：{', '.join(broker['role'])}
 - 常见指标：{', '.join(broker['常见指标'])}
 - 常见异常日志关键词：{', '.join(broker['常见异常日志关键词'])}
")
# Controller 知识 controller = ROCKETMQ_KNOWLEDGE['controller'] prompt_lines.append(f"3. Controller
 - 作用：{controller['作用']}
 - 常见日志关键词：{', '.join(controller['常见日志关键词'])}
")
# Common Actions prompt_lines.append("4. 常见故障排查动作") for reason, actions in ROCKETMQ_KNOWLEDGE['common_actions'].items(): prompt_lines.append(f" - {reason}：{', '.join(actions)}")
# K8s 部署知识 k8s = ROCKETMQ_KNOWLEDGE['k8s_deployment'] prompt_lines.append(f"5. Kubernetes 部署知识
 - {k8s['说明']}") for comp_name, comp in k8s['组件'].items(): prompt_lines.append(f" - {comp_name.capitalize()}（{comp['类型']}）
 - Pod 容器：{', '.join(comp['pod_container'])}
 - 日志路径：{comp['日志路径']}
 - 管理方式：{', '.join(comp['管理方式'])}") prompt_lines.append(f" - 获取 Pod 命令：{k8s['kubectl_command']}
")
# 当前 Evidence if evidences: prompt_lines.append("6. 最新 Evidence：") for e in evidences: prompt_lines.append(f" - State: {e.get('state')}, Output: {e.get('output')}")
# 输出要求 prompt_lines.append("
任务说明： - 分析提供的日志、指标或 Tool 输出 - 判断是否存在 ISR 异常 - 输出 JSON 格式： { "is_isr_related": true|false, "abnormal_broker": "broker-name", "reason": "...", "suspected_root": "network|disk_io|jvm|controller|slave_lag|unknown", "next_state": "...", "confidence": 0.0 } - 必须结合日志内容和指标进行判断")
return '
'.join(prompt_lines)
# ----------------------------- # 示例运行 # ----------------------------- if __name__ == '__main__': sample_evidences = [ {"state": "CHECK_META", "output": {"is_isr_related": True}}, {"state": "CHECK_CONTROLLER_LOG", "output": {"log": "remove broker-b from ISR"}} ]
prompt = generate_agent_prompt(sample_evidences) print(prompt)

