import json import sys
from langchain_community.chat_models import ChatOllama
from chains.broker_log_chain import build_chain from models import BrokerLogAnalysis from router import route
def main(): # 使用ollama本地模型 llm = ChatOllama(model="qwen2.5:1.5b", temperature=0) chain = build_chain(llm)
# 检查是否有命令行参数 if len(sys.argv) > 1: # 命令行参数模式 broker_log = sys.argv[1] process_broker_log(broker_log, chain) else: # 交互式对话模式 interactive_mode(chain)
def process_broker_log(broker_log, chain): """处理单个broker日志""" print(f"处理日志:\n{broker_log}\n")
raw_response = chain.invoke({"broker_log": broker_log})
try: # 尝试解析为JSON格式 raw_content = raw_response.content analysis = BrokerLogAnalysis.model_validate_json(raw_content)
next_step = route(analysis) result = next_step({"analysis": analysis.dict()})
print("=== 分析结果 ===") print(f"问题类型: {analysis.is_isr_related}") print(f"问题描述: {analysis.problem_description}") print(f"建议操作: {analysis.suggested_actions}") print(f"路由结果: {result}")
except Exception as e: # 如果不是JSON格式，直接输出原始响应 print("=== Agent分析结果 ===") print(raw_response.content)
def interactive_mode(chain): """交互式对话模式""" print("=== Broker日志分析Agent ===") print("请输入broker日志进行分析（输入'quit'或'退出'结束程序）") print("-" * 50)
while True: try: user_input = input("\n输入你的问题: ").strip()
if user_input.lower() in ['quit', '退出', 'exit']: print("感谢使用，再见！") break
if not user_input: print("输入不能为空，请重新输入") continue
process_broker_log(user_input, chain)
except KeyboardInterrupt: print("\n\n程序被中断，再见！") break except Exception as e: print(f"处理过程中出现错误: {e}")
if __name__ == "__main__": main()

