{"rawEvent":{"message_id":"019c2bee50d27e16bd6cba7a70901fac","conversation_id":"019c0cc4f5a670a4860e31f28421b495","tool_call_id":"call_74e9eeb6-4d64-4a15-a99e-fe18920c4a39","document":{"file_path":"/Users/tigerweili/github_tiger/06-Aether/chains/broker_log_chain.py","sub_content":"broker_log_chain.py","sub_content_event":"open_editor","sub_content_event_value":"/Users/tigerweili/github_tiger/06-Aether/chains/broker_log_chain.py","sub_content_tip":"/Users/tigerweili/github_tiger/06-Aether/chains/broker_log_chain.py","old_string":"def parse_analysis_result(raw_response) -> RocketMQAnalysis:
 """解析分析结果"""
