import json import os import re
COMMANDS = [ "topicRoute", "topicStatus", "topicClusterList", "brokerStatus", "queryMsgById", "queryMsgByKey", "queryMsgByUniqueKey", "queryMsgByOffset", "queryMsgTraceById", "printMsg", "brokerConsumeStats", "browseMessage", "producerConnection", "consumerConnection", "consumerProgress", "consumerStatus", "clusterList", "topicList", "statsAll", "allocateMQ", "checkMsgSendRT", "clusterRT", "getNamesrvConfig", "getBrokerConfig", "getConsumerConfig", "clusterAclConfigVersion", "haStatus", "getSyncStateSet", "getBrokerEpoch", "getControllerMetaData", "getControllerConfig", "getAcl", "listAcl", "consumer", "queryTopicRouteRules", "getConsumerOffset", "getConsumerOffsetByGroup", ]
BASE = ( "kubectl exec -it -n tce ocloud-tdmq-rocketmq5-namesrv-0 " "-c ocloud-tdmq-rocketmq5-namesrv -- bin/mqadmin " )
def parse_params(output: str): params = [] for line in output.splitlines(): line = line.rstrip() m = re.match(r"\\s*(-\\w)(?:,\\s*(--[\\w-]+))?\\s+(.+)", line) if m: params.append({ "flag": m.group(1), "long_flag": m.group(2), "desc": m.group(3).strip(), }) return params
def run_shell(cmd: str) -> str: with os.popen(cmd) as f: return f.read()
def main(): specs = {} for cmd in COMMANDS: full_cmd = f"{BASE}{cmd}" output = run_shell(full_cmd) specs[cmd] = { "params": parse_params(output), "raw": output[:2000], } print(json.dumps(specs, ensure_ascii=False, indent=2))
if __name__ == "__main__": main()
